// Build a Finding-API URL per card. Keywords combine set + card_name +
// card_number for tight targeting; the parser later validates by string-match.
//
// SECURITY-APPNAME is the eBay App ID from the same credential pair used
// by the vintage scrapers (Basic-auth value SGF5...NjZhNA== base64-decodes to
// 'HaydenHa-TEAMROCK-PRD-8183ec2e3-e8d59599:PRD-183ec2e31e2b-...'; the part
// before the colon is the App ID, which is all the Finding API needs).

const APP_ID = 'HaydenHa-TEAMROCK-PRD-8183ec2e3-e8d59599';
const FINDING_BASE = 'https://svcs.ebay.com/services/search/FindingService/v1';

function buildKeywords(card) {
  const parts = ['pokemon'];
  if (card.set_name) parts.push('"' + card.set_name + '"');
  if (card.card_name) parts.push('"' + card.card_name + '"');
  if (card.card_number) parts.push(String(card.card_number));
  return parts.join(' ');
}

function buildUrl(card) {
  const keywords = buildKeywords(card);
  // URLSearchParams isn't exposed in n8n's Code node sandbox — build the
  // query string manually with encodeURIComponent (which IS available).
  const params = [
    ['OPERATION-NAME', 'findCompletedItems'],
    ['SERVICE-VERSION', '1.13.0'],
    ['SECURITY-APPNAME', APP_ID],
    ['GLOBAL-ID', 'EBAY-US'],
    ['RESPONSE-DATA-FORMAT', 'JSON'],
    ['REST-PAYLOAD', 'true'],
    ['keywords', keywords],
    ['categoryId', '2536'],
    ['itemFilter(0).name', 'SoldItemsOnly'],
    ['itemFilter(0).value', 'true'],
    ['sortOrder', 'EndTimeSoonest'],
    ['paginationInput.entriesPerPage', '100']
  ];
  const qs = params
    .map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v))
    .join('&');
  return FINDING_BASE + '?' + qs;
}

return $input.all().map(({ json: card }) => ({
  json: {
    card_id: card.card_id,
    card_code: card.card_code,
    card_name: card.card_name,
    set_name: card.set_name,
    card_number: card.card_number,
    edition: card.edition,
    keywords: buildKeywords(card),
    search_url: buildUrl(card)
  }
}));

// Parse Finding API responses into ebay_transactions rows.
//
// Finding API JSON quirks:
//   - Every leaf value is wrapped in a 1-element array
//   - Numbers come as strings
//   - Currency price lives at sellingStatus[0].currentPrice[0].__value__
//   - endTime is ISO 8601 UTC
//
// Each result row inherits the SEARCHED card's identity (card_id,
// card_code, card_name, set_name, card_number, edition). The searched
// card's keywords were tight enough to expect mostly-correct results;
// false positives are accepted in v1.
//
// Grader+grade: parsed from listing title. Only emit canonical pairs that
// definitely exist in master_grade_catalog (PSA/CGC/BGS/SGC + 0.5-step
// grades 1..10). If parsing fails on either, BOTH are emitted as NULL so
// the (grader, grade) → master_grade_catalog FK doesn't reject the row.
//
// Input/card mapping: the HTTP node iterates 1:1 over Build Search URLs'
// 33 outputs, so resp[i] corresponds to builds[i]. We zip the two arrays
// rather than relying on $itemIndex (which only exists in 'Run Once for
// Each Item' mode; this Code node runs in default 'Run Once for All Items'
// mode).

function firstValue(arr) {
  if (!arr) return null;
  if (Array.isArray(arr) && arr.length > 0) return arr[0];
  return arr;
}

function toNumber(v) {
  if (v === null || v === undefined) return null;
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : null;
}

function parseGraderGrade(title) {
  if (!title) return { grader: null, grade: null };
  const m = title.match(/\b(PSA|CGC|BGS|SGC)\s*(10|9\.5|9|8\.5|8|7\.5|7|6\.5|6|5\.5|5|4\.5|4|3\.5|3|2\.5|2|1\.5|1)\b/i);
  if (!m) return { grader: null, grade: null };
  return { grader: m[1].toUpperCase(), grade: m[2] };
}

function deriveSaleType(listingType) {
  // findCompletedItems listingType values:
  //   Auction, AuctionWithBIN → v2 'auction'
  //   FixedPrice, StoreInventory → v2 'fixed_price'
  //   AdFormat, Classified → default to 'fixed_price'
  if (!listingType) return 'fixed_price';
  const t = String(listingType).toLowerCase();
  if (t.includes('auction')) return 'auction';
  return 'fixed_price';
}

const inputs = $input.all();
const builds = $('Build Search URLs').all();
const out = [];

for (let i = 0; i < inputs.length; i++) {
  const card = (builds[i] && builds[i].json) || {};
  const resp = (inputs[i] && inputs[i].json) || {};

  const root = firstValue(resp.findCompletedItemsResponse) || {};
  const ack = firstValue(root.ack);
  if (ack !== 'Success' && ack !== 'Warning') continue;

  const searchResult = firstValue(root.searchResult) || {};
  const items = searchResult.item || [];

  for (const item of items) {
    const itemId = firstValue(item.itemId);
    if (!itemId) continue;

    const title = firstValue(item.title);
    const url = firstValue(item.viewItemURL);
    const galleryURL = firstValue(item.galleryURL);

    const sellingStatus = firstValue(item.sellingStatus) || {};
    const currentPrice = firstValue(sellingStatus.currentPrice) || {};
    const soldPrice = toNumber(currentPrice.__value__);
    const currency = currentPrice['@currencyId'] || 'USD';

    const listingInfo = firstValue(item.listingInfo) || {};
    const endTime = firstValue(listingInfo.endTime);
    const startTime = firstValue(listingInfo.startTime);
    const listingType = firstValue(listingInfo.listingType);

    const sellerInfo = firstValue(item.sellerInfo) || {};
    const sellerUsername = firstValue(sellerInfo.sellerUserName);
    const sellerFeedbackPct = toNumber(firstValue(sellerInfo.positiveFeedbackPercent));

    const condition = firstValue(item.condition) || {};
    const conditionName = firstValue(condition.conditionDisplayName);

    const { grader, grade } = parseGraderGrade(title);
    const saleType = deriveSaleType(listingType);

    out.push({
      json: {
        item_id: itemId,
        card_id: card.card_id,
        card_code: card.card_code,
        card_name: card.card_name,
        set_name: card.set_name,
        card_number: card.card_number,
        edition: card.edition,
        grader,
        grade,
        platform: 'ebay',
        currency,
        sold_price: soldPrice,
        listed_price: soldPrice,
        sold_at: endTime,
        listed_at: startTime,
        sale_type: saleType,
        seller_username: sellerUsername,
        seller_feedback_pct: sellerFeedbackPct,
        title_raw: title,
        condition: conditionName,
        raw_payload: JSON.stringify(item)
      }
    });
  }
}

return out;
